1	import { useSearchParams } from "react-router-dom";
2	import { Link2, MessageSquare, Sparkles, Settings, Receipt, FileSignature } from "lucide-react";
3	import { motion, AnimatePresence } from "framer-motion";
4	import { cn } from "@/lib/utils";
5	import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
6	
7	// Tab content
8	import CreviaLink from "./CreviaLink";
9	import SmartInvoicesTab from "@/components/studio/SmartInvoicesTab";
10	import ContractsTab from "@/components/studio/ContractsTab";
11	import StudioSettingsTab from "@/components/studio/StudioSettingsTab";
12	import StudioWorkspacesHub from "@/components/studio/workspaces/StudioWorkspacesHub";
13	
14	const CreviaStudio = () => {
15	  const [searchParams, setSearchParams] = useSearchParams();
16	
17	  const activeTab = searchParams.get("tab") || "link";
18	  const activeLinkSection = searchParams.get("section") || "profile";
19	  const activeWorkspace = searchParams.get("workspace") || undefined;
20	  const activeRoomId = searchParams.get("roomId") || undefined;
21	
22	  // Strict order: Link → Workspace → Invoice → Contracts → Settings
23	  const studioTabs = [
24	    { id: "link",      label: "Crevia Link", icon: Link2 },
25	    { id: "chat",      label: "Workspace",   icon: MessageSquare },
26	    { id: "invoices",  label: "Invoice",     icon: Receipt },
27	    { id: "contracts", label: "Canvas",       icon: FileSignature },
28	    { id: "settings",  label: "Settings",    icon: Settings },
29	  ];
30	
31	  const linkSections = [
32	    { id: "profile",    label: "Profile" },
33	    { id: "buttons",    label: "Buttons" },
34	    { id: "appearance", label: "Appearance" },
35	    { id: "settings",   label: "Settings" },
36	    { id: "analytics",  label: "Analytics" },
37	  ];
38	
39	  const handleTabChange = (tabId: string) => {
40	    setSearchParams({ tab: tabId });
41	  };
42	
43	  const handleLinkSectionChange = (sectionId: string) => {
44	    setSearchParams({ tab: "link", section: sectionId });
45	  };
46	
47	  const isChatTab = activeTab === "chat";
48	
49	  return (
50	    <div className="h-full flex flex-col bg-background">
51	      {/* Studio Header — flex-shrink-0 keeps it pinned while content below scrolls */}
52	      <div className="border-b border-border bg-background z-30 flex-shrink-0">
53	        <div className="mx-auto w-full max-w-7xl px-4 py-3 md:px-6 md:py-4">
54	          <div className="flex items-center gap-3 mb-3 md:mb-4">
55	            <div className="p-1.5 md:p-2 rounded-xl bg-bronze/10">
56	              <Sparkles className="h-4 w-4 md:h-5 md:w-5 text-bronze" />
57	            </div>
58	            <div>
59	              <h1 className="font-vollkorn text-xl md:text-2xl font-semibold text-foreground">
60	                Crevia Studio
61	              </h1>
62	              <p className="text-sm md:text-base text-muted-foreground">
63	                Your creative business toolkit
64	              </p>
65	            </div>
66	          </div>
67	
68	          {/* Tabs — strict order enforced by studioTabs array */}
69	          <ScrollArea className="w-full">
70	            <div className="flex items-center gap-1 pb-1 -mb-px">
71	              {studioTabs.map((tab) => {
72	                const Icon = tab.icon;
73	                const isActive = activeTab === tab.id;
74	                return (
75	                  <button
76	                    key={tab.id}
77	                    onClick={() => handleTabChange(tab.id)}
78	                    title={tab.label}
79	                    className={cn(
80	                      "flex items-center gap-1.5 px-3 py-2.5 rounded-t-lg font-poppins text-sm font-medium whitespace-nowrap transition-all duration-300 min-w-[44px] justify-center",
81	                      isActive
82	                        ? "bg-bronze/10 text-bronze border-b-2 border-bronze"
83	                        : "text-muted-foreground hover:text-foreground hover:bg-muted/50"
84	                    )}
85	                  >
86	                    <Icon className="h-4 w-4 flex-shrink-0" />
87	                    <span className="hidden sm:inline">{tab.label}</span>
88	                  </button>
89	                );
90	              })}
91	            </div>
92	            <ScrollBar orientation="horizontal" className="h-1.5" />
93	          </ScrollArea>
94	
95	          {/* Link sub-sections (mobile only) — segmented control */}
96	          {activeTab === "link" && (
97	            <div className="md:hidden mt-2 border-t border-border/40 pt-2">
98	              {/* Row 1: Profile · Buttons · Appearance */}
99	              <div className="flex gap-1 p-1 bg-muted/60 rounded-xl mb-1">
100	                {linkSections.slice(0, 3).map((section) => (
101	                  <button
102	                    key={section.id}
103	                    type="button"
104	                    onClick={() => handleLinkSectionChange(section.id)}
105	                    className={cn(
106	                      "flex-1 py-1.5 rounded-lg text-[11px] font-semibold text-center transition-all duration-200 active:scale-95",
107	                      activeLinkSection === section.id
108	                        ? "bg-background text-foreground shadow-sm"
109	                        : "text-muted-foreground"
110	                    )}
111	                  >
112	                    {section.label}
113	                  </button>
114	                ))}
115	              </div>
116	              {/* Row 2: Settings · Analytics */}
117	              <div className="flex gap-1 p-1 bg-muted/60 rounded-xl">
118	                {linkSections.slice(3).map((section) => (
119	                  <button
120	                    key={section.id}
121	                    type="button"
122	                    onClick={() => handleLinkSectionChange(section.id)}
123	                    className={cn(
124	                      "flex-1 py-1.5 rounded-lg text-[11px] font-semibold text-center transition-all duration-200 active:scale-95",
125	                      activeLinkSection === section.id
126	                        ? "bg-background text-foreground shadow-sm"
127	                        : "text-muted-foreground"
128	                    )}
129	                  >
130	                    {section.label}
131	                  </button>
132	                ))}
133	              </div>
134	            </div>
135	          )}
136	        </div>
137	      </div>
138	
139	      {/* Tab Content */}
140	      {isChatTab ? (
141	        <div className="flex-1 min-h-0 overflow-hidden">
142	          <StudioWorkspacesHub initialRoomId={activeRoomId} />
143	        </div>
144	      ) : (
145	        <div className="flex-1 overflow-y-auto min-w-0">
146	          <AnimatePresence mode="wait">
147	            <motion.div
148	              key={activeTab}
149	              initial={{ opacity: 0, y: 8 }}
150	              animate={{ opacity: 1, y: 0 }}
151	              exit={{ opacity: 0, y: -6 }}
152	              transition={{ duration: 0.3, ease: [0.25, 0.46, 0.45, 0.94] }}
153	            >
154	              {activeTab === "link"      && <CreviaLink isEmbedded />}
155	              {activeTab === "invoices"  && <SmartInvoicesTab workspaceId={activeWorkspace} />}
156	              {activeTab === "contracts" && <ContractsTab workspaceId={activeWorkspace} />}
157	              {activeTab === "settings"  && <StudioSettingsTab />}
158	            </motion.div>
159	          </AnimatePresence>
160	        </div>
161	      )}
162	    </div>
163	  );
164	};
165	
166	export default CreviaStudio;
