1	import { useState, useEffect } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { motion, AnimatePresence } from "framer-motion";
4	import {
5	  MessageSquare,
6	  ArrowLeft,
7	  Sparkles,
8	  Loader2,
9	  Users,
10	  UserPlus,
11	} from "lucide-react";
12	import { Button } from "@/components/ui/button";
13	import { Input } from "@/components/ui/input";
14	import {
15	  Dialog,
16	  DialogContent,
17	  DialogHeader,
18	  DialogTitle,
19	} from "@/components/ui/dialog";
20	import { toast } from "sonner";
21	import { cn } from "@/lib/utils";
22	import CreviaChat from "@/components/crevia-connect/shared/CreviaChat";
23	import WorkspaceInboxList from "./WorkspaceInboxList";
24	import WorkspaceMembersDialog from "./WorkspaceMembersDialog";
25	
26	interface SelectedRoom {
27	  id: string;
28	  name: string | null;
29	  type: "workspace" | "dm";
30	  created_by?: string;
31	  memberCount?: number;
32	}
33	
34	const StudioWorkspacesHub = ({ initialRoomId }: { initialRoomId?: string } = {}) => {
35	  const [userId, setUserId] = useState("");
36	  const [selectedRoom, setSelectedRoom] = useState<SelectedRoom | null>(null);
37	  const [showMobileChat, setShowMobileChat] = useState(false);
38	  const [memberCount, setMemberCount] = useState(1);
39	
40	  // Members dialog (Add People)
41	  const [membersDialogOpen, setMembersDialogOpen] = useState(false);
42	
43	  // Propose workspace dialog (DM → workspace invite)
44	  const [proposeDialogOpen, setProposeDialogOpen] = useState(false);
45	  const [proposeName, setProposeName] = useState("");
46	  const [proposeSending, setProposeSending] = useState(false);
47	
48	  useEffect(() => {
49	    supabase.auth.getUser().then(({ data: { user } }) => {
50	      if (user) setUserId(user.id);
51	    });
52	  }, []);
53	
54	  // Auto-select when navigated from notification / external link
55	  useEffect(() => {
56	    if (!initialRoomId || !userId) return;
57	    supabase
58	      .from("chat_rooms")
59	      .select("id, name, is_group, created_by")
60	      .eq("id", initialRoomId)
61	      .single()
62	      .then(({ data: room }) => {
63	        if (room) {
64	          handleSelectRoom(
65	            { id: room.id, name: room.name, created_by: room.created_by },
66	            room.name ? "workspace" : "dm"
67	          );
68	        }
69	      });
70	  // eslint-disable-next-line react-hooks/exhaustive-deps
71	  }, [initialRoomId, userId]);
72	
73	  const handleSelectRoom = async (
74	    room: { id: string; name: string | null; created_by?: string; memberCount?: number },
75	    type: "workspace" | "dm"
76	  ) => {
77	    setSelectedRoom({ ...room, type });
78	    setShowMobileChat(true);
79	    setMembersDialogOpen(false);
80	
81	    // Fetch member count for the workspace header
82	    if (type === "workspace") {
83	      const { count } = await supabase
84	        .from("chat_room_members")
85	        .select("*", { count: "exact", head: true })
86	        .eq("room_id", room.id);
87	      setMemberCount(count ?? 1);
88	    }
89	  };
90	
91	  const handleProposeWorkspace = async () => {
92	    if (!selectedRoom || !userId || !proposeName.trim()) return;
93	    setProposeSending(true);
94	    const { error } = await supabase.from("chat_messages").insert({
95	      room_id: selectedRoom.id,
96	      sender_id: userId,
97	      message_type: "workspace_invite",
98	      content: JSON.stringify({ status: "pending", workspace_name: proposeName.trim() }),
99	      is_encrypted: false,
100	    });
101	    setProposeSending(false);
102	    if (error) {
103	      toast.error("Failed to send workspace invite");
104	    } else {
105	      toast.success("Workspace invite sent!");
106	      setProposeDialogOpen(false);
107	      setProposeName("");
108	    }
109	  };
110	
111	  const isWorkspace = selectedRoom?.type === "workspace";
112	  const isDm = selectedRoom?.type === "dm";
113	
114	  return (
115	    <div className="flex h-full w-full overflow-hidden bg-background">
116	      {/* ── PANE 1: Inbox ── */}
117	      <div
118	        className={cn(
119	          "flex-shrink-0 border-r border-gray-100 dark:border-border/60",
120	          showMobileChat ? "hidden md:flex" : "flex w-full md:w-auto"
121	        )}
122	      >
123	        {userId && (
124	          <WorkspaceInboxList
125	            selectedRoomId={selectedRoom?.id ?? null}
126	            onSelectRoom={handleSelectRoom}
127	            userId={userId}
128	          />
129	        )}
130	      </div>
131	
132	      {/* ── PANE 2: Chat / empty state ── */}
133	      <div
134	        className={cn(
135	          "flex flex-col min-h-0 min-w-0 overflow-hidden flex-1",
136	          showMobileChat ? "flex" : "hidden md:flex"
137	        )}
138	      >
139	        {/* Mobile back */}
140	        <div className="md:hidden flex-shrink-0 px-3 py-2 border-b border-gray-100 dark:border-border/50">
141	          <button
142	            onClick={() => setShowMobileChat(false)}
143	            className="flex items-center gap-1.5 text-xs text-muted-foreground hover:text-foreground transition-colors"
144	          >
145	            <ArrowLeft className="w-4 h-4" />
146	            All messages
147	          </button>
148	        </div>
149	
150	        {/* Workspace action bar — shows above chat for workspaces */}
151	        <AnimatePresence>
152	          {isWorkspace && selectedRoom && (
153	            <motion.div
154	              key="ws-bar"
155	              initial={{ opacity: 0, height: 0 }}
156	              animate={{ opacity: 1, height: "auto" }}
157	              exit={{ opacity: 0, height: 0 }}
158	              transition={{ duration: 0.16 }}
159	              className="flex-shrink-0 border-b border-gray-100 dark:border-border/50 px-4 py-2 flex items-center justify-between gap-2 overflow-hidden bg-card/40"
160	            >
161	              <div className="flex items-center gap-2 min-w-0">
162	                <div className="w-6 h-6 rounded-lg bg-bronze/10 flex items-center justify-center flex-shrink-0">
163	                  <Sparkles className="w-3 h-3 text-bronze" />
164	                </div>
165	                <span className="text-xs font-semibold truncate text-foreground/80">
166	                  {selectedRoom.name ?? "Workspace"}
167	                </span>
168	                <span className="text-[10px] text-muted-foreground/50 flex-shrink-0 flex items-center gap-1">
169	                  <Users className="w-2.5 h-2.5" />
170	                  {memberCount}
171	                </span>
172	              </div>
173	
174	              {/* Add People — prominent, always visible */}
175	              <Button
176	                size="sm"
177	                onClick={() => setMembersDialogOpen(true)}
178	                className="h-7 text-xs gap-1.5 bg-bronze hover:bg-bronze/90 text-background font-semibold flex-shrink-0"
179	              >
180	                <UserPlus className="w-3 h-3" />
181	                Add People
182	              </Button>
183	            </motion.div>
184	          )}
185	
186	          {/* DM toolbar — Propose Workspace */}
187	          {isDm && (
188	            <motion.div
189	              key="dm-bar"
190	              initial={{ opacity: 0, height: 0 }}
191	              animate={{ opacity: 1, height: "auto" }}
192	              exit={{ opacity: 0, height: 0 }}
193	              transition={{ duration: 0.16 }}
194	              className="flex-shrink-0 border-b border-gray-100 dark:border-border/50 px-4 py-2 flex items-center gap-2 overflow-hidden"
195	            >
196	              <Button
197	                size="sm"
198	                variant="outline"
199	                onClick={() => { setProposeName(""); setProposeDialogOpen(true); }}
200	                className="h-7 text-xs gap-1.5 border-bronze/30 text-bronze hover:bg-bronze/8 hover:border-bronze/50 font-medium"
201	              >
202	                <Sparkles className="w-3 h-3" />
203	                Propose Workspace
204	              </Button>
205	              <span className="text-[10px] text-muted-foreground/50">
206	                Invite this person to a deal room
207	              </span>
208	            </motion.div>
209	          )}
210	        </AnimatePresence>
211	
212	        {/* Main content */}
213	        <div className="flex-1 min-h-0 overflow-hidden">
214	          <AnimatePresence mode="wait">
215	            {selectedRoom ? (
216	              <motion.div
217	                key={selectedRoom.id}
218	                initial={{ opacity: 0 }}
219	                animate={{ opacity: 1 }}
220	                exit={{ opacity: 0 }}
221	                transition={{ duration: 0.15 }}
222	                className="h-full flex flex-col"
223	              >
224	                <CreviaChat
225	                  externalRoomId={selectedRoom.id}
226	                  hideRoomList
227	                  onBack={() => setShowMobileChat(false)}
228	                />
229	              </motion.div>
230	            ) : (
231	              <motion.div
232	                key="empty"
233	                initial={{ opacity: 0 }}
234	                animate={{ opacity: 1 }}
235	                className="h-full flex flex-col items-center justify-center text-center p-8"
236	              >
237	                <div className="w-16 h-16 rounded-2xl bg-bronze/8 dark:bg-bronze/10 flex items-center justify-center mb-4">
238	                  <MessageSquare className="w-7 h-7 text-bronze/40" />
239	                </div>
240	                <h3 className="font-semibold text-sm mb-1.5 tracking-tight">
241	                  Select a conversation
242	                </h3>
243	                <p className="text-[12px] text-muted-foreground max-w-[240px] leading-relaxed">
244	                  Choose a workspace or direct message from the list to open the thread.
245	                </p>
246	              </motion.div>
247	            )}
248	          </AnimatePresence>
249	        </div>
250	      </div>
251	
252	      {/* Members dialog */}
253	      {selectedRoom && isWorkspace && (
254	        <WorkspaceMembersDialog
255	          open={membersDialogOpen}
256	          onOpenChange={setMembersDialogOpen}
257	          roomId={selectedRoom.id}
258	          createdBy={selectedRoom.created_by ?? ""}
259	          currentUserId={userId}
260	        />
261	      )}
262	
263	      {/* Propose Workspace dialog */}
264	      <Dialog open={proposeDialogOpen} onOpenChange={(o) => { if (!o) setProposeDialogOpen(false); }}>
265	        <DialogContent className="max-w-sm">
266	          <DialogHeader>
267	            <div className="flex items-center gap-2 mb-1">
268	              <div className="p-1.5 rounded-lg bg-bronze/10">
269	                <Sparkles className="w-4 h-4 text-bronze" />
270	              </div>
271	              <DialogTitle className="text-sm font-semibold">Name the Workspace</DialogTitle>
272	            </div>
273	          </DialogHeader>
274	          <p className="text-xs text-muted-foreground mb-3">
275	            Give this deal room a name. The other person will see it when they accept.
276	          </p>
277	          <Input
278	            value={proposeName}
279	            onChange={(e) => setProposeName(e.target.value)}
280	            placeholder="e.g. Nike x Crevia Campaign"
281	            className="h-9 text-sm"
282	            autoFocus
283	            onKeyDown={(e) => { if (e.key === "Enter" && !proposeSending) handleProposeWorkspace(); }}
284	          />
285	          <div className="flex gap-2 justify-end mt-2">
286	            <Button variant="outline" size="sm" onClick={() => setProposeDialogOpen(false)} disabled={proposeSending}>
287	              Cancel
288	            </Button>
289	            <Button
290	              size="sm"
291	              onClick={handleProposeWorkspace}
292	              disabled={!proposeName.trim() || proposeSending}
293	              className="bg-bronze hover:bg-bronze/90 text-background font-semibold gap-1.5"
294	            >
295	              {proposeSending
296	                ? <span className="w-3.5 h-3.5 border-2 border-background/40 border-t-background rounded-full animate-spin" />
297	                : <Sparkles className="w-3.5 h-3.5" />}
298	              Send Invite
299	            </Button>
300	          </div>
301	        </DialogContent>
302	      </Dialog>
303	    </div>
304	  );
305	};
306	
307	export default StudioWorkspacesHub;
