1	import { Link2, MessageSquare, Settings } from "lucide-react";
2	import { cn } from "@/lib/utils";
3	import {
4	  Tooltip,
5	  TooltipContent,
6	  TooltipProvider,
7	  TooltipTrigger,
8	} from "@/components/ui/tooltip";
9	
10	interface StudioIconNavProps {
11	  activeTab: string;
12	  onNavigate: (tab: string) => void;
13	}
14	
15	const NAV_ITEMS = [
16	  { id: "link", label: "Crevia Link", icon: Link2 },
17	  { id: "chat", label: "Workspaces", icon: MessageSquare },
18	  { id: "settings", label: "Settings", icon: Settings },
19	];
