26	          <Tooltip key={id}>
27	            <TooltipTrigger asChild>
28	              <button
29	                onClick={() => onNavigate(id)}
30	                className={cn(
31	                  "w-9 h-9 flex items-center justify-center rounded-xl transition-all duration-200 ease-out",
32	                  activeTab === id
33	                    ? "bg-bronze/15 text-bronze shadow-sm"
34	                    : "text-muted-foreground/70 hover:bg-muted hover:text-foreground"
35	                )}
36	              >
37	                <Icon className="w-[17px] h-[17px]" />
38	              </button>
39	            </TooltipTrigger>
40	            <TooltipContent side="right" className="text-xs font-medium">
41	              {label}
42	            </TooltipContent>
43	          </Tooltip>
44	        ))}
45	      </nav>
46	    </TooltipProvider>
47	  );
48	};
49	
50	export default StudioIconNav;
