4	import { Input } from "@/components/ui/input";
5	import { Badge } from "@/components/ui/badge";
6	import { ScrollArea } from "@/components/ui/scroll-area";
7	import {
8	  Dialog,
9	  DialogContent,
10	  DialogHeader,
11	  DialogTitle,
12	} from "@/components/ui/dialog";
13	import { motion } from "framer-motion";
14	import { Search, Plus, MessageSquare, Users, Sparkles, Loader2, MoreHorizontal, Pencil, Trash2 } from "lucide-react";
15	import {
16	  DropdownMenu,
17	  DropdownMenuContent,
18	  DropdownMenuItem,
19	  DropdownMenuSeparator,
20	  DropdownMenuTrigger,
21	} from "@/components/ui/dropdown-menu";
22	import {
23	  AlertDialog,
24	  AlertDialogAction,
25	  AlertDialogCancel,
26	  AlertDialogContent,
27	  AlertDialogDescription,
28	  AlertDialogFooter,
