33	
34	const avatarStyle = (seed: string): React.CSSProperties => {
35	  let hash = 0;
36	  for (let i = 0; i < seed.length; i++) {
37	    hash = seed.charCodeAt(i) + ((hash << 5) - hash);
38	  }
39	  const hue = Math.abs(hash) % 360;
40	  return { background: `hsl(${hue},55%,65%)`, color: `hsl(${hue},55%,22%)` };
41	};
42	import { formatDistanceToNow } from "date-fns";
43	import { toast } from "sonner";
44	
45	interface Room {
46	  id: string;
47	  name: string | null;
48	  is_group: boolean;
49	  created_by: string;
50	  updated_at: string;
51	  avatar_url: string | null;
52	  memberCount?: number;
53	  dmPartnerName?: string | null;
54	  dmPartnerAvatar?: string | null;
55	  dmPartnerInitial?: string;
56	  memberUserIds?: string[];
57	}
58	
59	interface WorkspaceInboxListProps {
60	  selectedRoomId: string | null;
61	  onSelectRoom: (room: Room, type: "workspace" | "dm") => void;
62	  userId: string;
63	}
64	
